"""
MKT Original — Luke chapters 14–16
Output: data/commentary/mkt-original/luke.json
Run: python3 scripts/zc-original-luke-14-16.py

Key linguistic nodes:
- 14:2: hydrōpikos (dropsy — only NT occurrence)
- 14:11: the tapeinoō/hypsoō reversal formula
- 14:26: miseō as Semitic idiom for comparative love
- 14:34: halas/mōrainō — salt-losing-saltness paradox
- 15:13: asōtōs (prodigally, recklessly — from asōtia)
- 15:17: eis heauton de elthōn (coming to himself)
- 15:20: esplanchnisthē (visceral compassion) — already present; merge skips
- 16:8: phronimōs (shrewdly) and the ironic commendation
- 16:9: mamōnas — Aramaic loanword for wealth/money
- 16:16: biazetai (forces its way in — middle or passive; debated)
- 16:22: Abraam kolpon (Abraham's bosom/side — hapax)
- 16:23: hadēs — Greek underworld term adopted into Jewish afterlife vocabulary
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys.
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

LUKE_CH14_16 = {
  "14": {
    "1": '<p><strong>en tō elthein auton eis oikon tinos tōn archontōn tōn Pharisaiōn sabbatō phagein arton</strong> — the construction <em>en tō + infinitive</em> is Luke\'s favored temporal frame (also 3:21; 9:18; 9:29); here it introduces a Sabbath dinner at the house of a ruling Pharisee. <em>Archontōn</em> (rulers, leaders — from <em>archō</em> = rule) denotes a senior Pharisee; this is not an ordinary householder but a prominent figure in the local community. <strong>autoi ēsan paratērumenoi auton</strong> — they were watching him — <em>paratēreō</em> (watch carefully, observe closely — from <em>para-</em> + <em>tēreō</em> = keep, guard; watching alongside) has a hostile surveillance nuance throughout Luke (6:7; 20:20); they are monitoring for violations, not simply curious.</p>',
    "2": '<p><strong>anthrōpos tis ēn hydrōpikos</strong> — a certain man was dropsical — <em>hydrōpikos</em> (suffering from dropsy, abnormal fluid retention — from <em>hydōr</em> = water) is a hapax legomenon in the NT; this is the only occurrence of the term in the entire NT. Luke\'s medical vocabulary (cf. <em>puretos</em> at 4:38-39; <em>lepra</em> at 5:12; <em>paralytikos</em> at 5:24) reflects the tradition of his medical interest. Dropsy (<em>hydrops</em> in ancient medicine) is excess fluid in the body, often a symptom of cardiac, renal, or liver failure; visible, chronic, and socially limiting in an honor-shame society.</p>',
    "3": '<p><strong>exestin tō sabbatō therapeusai ē ou</strong> — is it lawful to heal on the Sabbath or not — Jesus\'s direct question short-circuits the trap; instead of acting first and being accused, he poses the legal question to the legal experts. <em>Exesti</em> (it is lawful, permissible) is the standard Sabbath-dispute verb (also 6:2, 4, 9; 14:3); the question places the burden of answer on the Pharisees. The <em>ē ou</em> (or not) forces a binary judgment where any answer creates legal difficulty for them.</p>',
    "4": '<p><strong>hoi de hēsychasan</strong> — they remained silent — <em>hēsychasan</em> (aorist of <em>hēsychazō</em> = be quiet, be still; also 23:56 for the women resting on the Sabbath) signals deliberate non-response. The legal experts who are there to trap Jesus cannot answer his question without entangling themselves. <strong>epilabomenos iāsato auton kai apelysen</strong> — taking hold, he healed him and released him — <em>epilambanō</em> (take hold of, grasp) is the deliberate physical contact that initiates healing; <em>apolyō</em> (release, let go, send away) dismisses the man after healing, ending the episode cleanly.</p>',
    "5": '<p><strong>tinos hymōn huios ē bous eis phrear peseitai</strong> — whose son or ox falls into a well — the a fortiori argument (qal wahomer): if you rescue an animal on the Sabbath, how much more rescue a person? Textual variants exist: some manuscripts read <em>onos</em> (donkey) instead of <em>huios</em> (son); the donkey-ox pair matches Matt 12:11 more closely, while son-ox is the harder reading (more dramatic and therefore more likely original). <em>Phrear</em> (pit, well — also John 4:11-12 for Jacob\'s well) is the specific emergency that Sabbath law already acknowledged: danger to life supersedes Sabbath restrictions.</p>',
    "6": '<p><strong>kai ouk ischusan antapokrithēnai pros tauta</strong> — they were not able to reply against these things — <em>antapokrinomai</em> (answer in return, reply against — compound: <em>anti-</em> + <em>apo-</em> + <em>krinomai</em>) describes a formal legal counter-argument; they cannot mount one. <em>Pros tauta</em> (against these things) — the demonstration of Sabbath mercy logic has left them without legal ground. The silence of v.4 (strategic) and the inability of v.6 (logical) together constitute Luke\'s portrait of religious expertise that cannot answer Jesus.</p>',
    "7": '<p><strong>elegon de pros tous keklēmenous parabolēn</strong> — he told a parable to those who were invited — <em>parabolē</em> (parable — from <em>paraballō</em> = throw alongside, compare) is the comparison-teaching form. <strong>epechōn pōs tas prōtoklisias exelegonto</strong> — noticing how they chose the places of honor — <em>epechō</em> (hold toward, pay attention to) + <em>prōtoklisia</em> (first-reclining-place, place of honor at table — from <em>prōtos</em> + <em>klisia</em> = first leaning-position); the choice of table position is an honor-competition visible to all observers. The dinner table in Mediterranean antiquity is a theater of social rank.</p>',
    "8": '<p><strong>mē kataklithēs eis tēn prōtoklisian</strong> — do not recline at the place of honor — <em>kataklithēs</em> (aorist passive subjunctive of <em>kataklinō</em> = make recline, recline) is the formal dining posture. <em>Mēpote entimoteros sou ē keklēmenos hyp autou</em> — lest a more honorable person than you has been invited — <em>entimos</em> (honored, esteemed — from <em>en</em> + <em>timē</em> = in honor) frames the social comparison: one\'s position at table must match one\'s social ranking, and presuming too high a position creates public shame when corrected.</p>',
    "9": '<p><strong>dos toutō topon</strong> — give this person your place — <em>topos</em> (place) is both the physical seat and the social position; the displacement is public and shaming. <strong>meta aischunēs ton eschaton topon katechein</strong> — to take the last place with shame — <em>aischunē</em> (shame, disgrace — the social negative of <em>timē</em>/honor) is the emotion of public dishonoring; <em>eschaton topon</em> (last place) is the social nadir. The sequence is: presumption → public correction → shame, the honor-shame culture\'s social worst-case.</p>',
    "10": '<p><strong>anabase epanō</strong> — move up higher — the ascending movement (<em>anabainō</em> = go up) in response to the host\'s invitation reverses the shame dynamic. <strong>tote estai soi doxa</strong> — then there will be glory/honor for you — <em>doxa</em> (glory, honor, repute — the highest honor-word) in the presence of all the other guests (<em>enōpion pantōn tōn sunanakeimenenōn</em>); the public scope of the honor is what makes it worth having. The parable maps the honor-culture\'s logic but redirects it: humble positioning before the host, not strategic self-promotion, wins honor.</p>',
    "11": '<p><strong>hoti pas ho hypsōn heauton tapeinōthēsetai kai ho tapeinōn heauton hypsōthēsetai</strong> — for everyone who exalts himself will be humbled and everyone who humbles himself will be exalted — this is Luke\'s recurring reversal formula (also 18:14; cf. 1:52); it occurs in Matthew without the <em>pas</em> (all/everyone). <em>Hypsoō</em> (exalt, lift high) and <em>tapeinoō</em> (humble, lower) are antonymous divine-action verbs in the LXX (Ezek 21:26; Job 5:11; Ps 75:7); the divine passive (future passives = God acts) declares that the reversals are not social happenstance but divine governance.</p>',
    "12": '<p><strong>mē phōnei tous philous sou mēde tous adelphous sou</strong> — do not invite your friends or your brothers — Jesus redefines the logic of hospitality from reciprocal exchange to non-reciprocal gift. The standard hospitality pattern in Mediterranean culture was charis-exchange: give to receive; the invited guest becomes socially obligated (<em>antapodoma soi genētai</em> = there will be a return-gift to you). Jesus\'s counter-instruction breaks the reciprocity cycle that structures the social order of honor exchange.</p>',
    "13": '<p><strong>ptōchous anapeirous chōlous typhlous kale</strong> — invite the poor, crippled, lame, blind — the four categories (<em>ptōchos, anapeiros, chōlos, typhlos</em>) are the same grouping that appear in the Great Banquet parable (v.21) and mirror the eschatological inclusion list of Isa 35:5-6 and Isa 61:1-2. <em>Anapeiros</em> (crippled, disabled — from <em>ana-</em> + <em>pēros</em> = maimed) appears only here and v.21 in the NT; it denotes a disability that prevents participation in normal social and economic life.</p>',
    "14": '<p><strong>makarios de esē hoti ouk echousin antapodounai soi</strong> — blessed are you because they cannot repay you — the beatitude (<em>makarios</em>) reframes the hospitality calculation: absence of repayment-ability is the condition of blessing, not a liability. <strong>antapodothēsetai gar soi en tē anastasei tōn dikaiōn</strong> — it will be repaid to you at the resurrection of the righteous — <em>antapodidōmi</em> (repay, recompense — compound of <em>anti-</em> + <em>apo-</em> + <em>didōmi</em>) is the reciprocity verb, but relocated to the eschaton: the divine repayment at the resurrection replaces the immediate social return. <em>Anastasis tōn dikaiōn</em> (resurrection of the righteous) reflects the Jewish apocalyptic expectation of a selective first resurrection (Dan 12:2; Acts 24:15).</p>',
    "15": '<p><strong>makarios hostis phagetai arton en tē basileia tou theou</strong> — blessed is the one who will eat bread in the kingdom of God — the table-guest\'s exclamation combines the <em>makarios</em>-formula with the kingdom-feast motif (Isa 25:6; also 13:29); it is a pious cliché that Jesus will immediately reframe. <em>Phagetai arton</em> (eat bread — idiomatic for "share a meal") in the eschatological context echoes the messianic banquet tradition in Second Temple Jewish texts (1 Enoch 62:14; 4 Ezra 7:36). Jesus\'s parable response implies: the question is not whether the feast happens but whether the invited will show up.</p>',
    "16": '<p><strong>anthrōpos tis epoiei deipnon mega kai ekalesen pollous</strong> — a certain man made a great banquet and invited many — <em>deipnon</em> (the main meal, dinner — the evening banquet; contrast <em>ariston</em> = morning meal) is the formal feast. The <em>mega</em> (great) qualifier signals extravagance and preparation. <em>Pollous</em> (many) identifies the invited group as a large, pre-arranged guest list; in Middle Eastern practice, formal invitations were extended in advance, with a second summons at the time of the meal to confirm attendance.</p>',
    "17": '<p><strong>erchou hoti ēdē hetoima estin panta</strong> — come, because everything is now ready — the two-stage invitation structure (invitation in advance + the servant\'s summons at serving-time) is the standard of formal ancient hospitality; the second summons is the moment of actual commitment. Refusing the second summons after accepting the first is a serious social offense — it dishonors the host publicly. <em>Ēdē hetoima</em> (already ready) emphasizes that the delay is purely on the guests\' side; the feast is prepared and waiting.</p>',
    "18": '<p><strong>kai ērxanto apo mias pantes paraiteisthai</strong> — they all alike began to make excuses — <em>apo mias</em> (from one, all at once — possibly <em>mias gnōmēs</em> = one mind; from one voice/accord) is a Semitic idiom for unanimity. <em>Paraiteisthai</em> (beg off, excuse oneself — from <em>para-</em> + <em>aiteomai</em> = request alongside; to ask to be excused) is the polite refusal verb. The first excuse: <em>agron ēgorasa</em> (I bought a field) + <em>exelthein idein</em> (I need to go see it) — the field was already purchased; this is not urgent, merely convenient.</p>',
    "19": '<p><strong>zeugē boōn ēgorasa pente kai poreuomai dokimasai auta</strong> — I bought five yoke of oxen and I\'m going to try them out — <em>zeugē boōn</em> (yoke of oxen — <em>zeugos</em> = paired/yoked; a yoke of oxen is a working pair) × 5 = ten oxen, a large agricultural investment. <em>Dokimasai</em> (test, examine, prove — from <em>dokimazō</em>; the word for evaluating a coin\'s genuineness) implies field-testing new equipment. The purchase was already made; the testing is post-hoc rather than time-critical. The excuse pattern mirrors the first: acquisition already complete, inspection merely convenient.</p>',
    "20": '<p><strong>gynaika egēma kai dia touto ou dunamai elthein</strong> — I married a wife and therefore I cannot come — the third excuse inverts the polite formula of the first two (the others apologized: <em>erōtō se, echē me parēitēmenon</em> = please have me excused); this one is a flat refusal without apology. Deut 20:7 and 24:5 exempted a newly married man from military service, but a private banquet is not war. The marriage excuse is the most brazen: no apology offered, no return-commitment made. The escalating rudeness of the three excuses narrates the guests\' growing disrespect for the host.</p>',
    "21": '<p><strong>tote orgistheis ho oikodespotēs eipen tō doulō autou</strong> — the master became angry and said to his servant — <em>orgizō</em> (be angry — the full-anger word; also Matt 18:34; 22:7) signals that the honor violation is complete. <strong>exelthe tacheōs eis tas plateias kai rhumas tēs poleōs</strong> — go out quickly into the streets and alleys of the city — <em>plateia</em> (broad street, main avenue) vs <em>rhymē</em> (narrow alley, lane — the back streets); the servant is to scour both the public main streets and the private back alleys. The replacement guests are the same four categories as v.13: poor, crippled, blind, lame — the socially excluded become the feast\'s recipients.</p>',
    "22": '<p><strong>gegonen ho epetaxas kai eti topos estin</strong> — what you ordered has been done and there is still room — <em>topos</em> (place, room, space) — the banquet hall has more capacity than the replacement guests have filled; the servant reports both compliance and remaining availability. The ongoing vacancy is the narrative setup for the third dispatch (v.23), expanding the invitation beyond the city to the roads and countryside. The feast\'s generosity exceeds even the first replacement population.</p>',
    "23": '<p><strong>anankason eiselthein</strong> — compel them to come in — <em>anankason</em> (aorist active imperative of <em>anankazō</em> = compel, force, constrain — from <em>anankē</em> = necessity) is the disputed word. In the patristic period Augustine cited this verse for compelling heretics into the church; Calvin and others rejected this use. The Greek sense is "urge strongly, press insistently" — the cultural background is the Middle Eastern hospitality dynamic where hosts must overcome their guests\' polite refusals with persistent invitation. <em>Hina gemisthē mou ho oikos</em> — so that my house will be full — the goal is fullness, abundance, the eschatological feast completed.</p>',
    "24": '<p><strong>oudeis tōn andrōn ekeinōn tōn keklēmenōn geusetal mou tou deipnou</strong> — not one of those men who were invited will taste my banquet — <em>geusasthai</em> (taste, experience — from <em>geuomai</em>) with the genitive <em>tou deipnou</em>: taste of my banquet (partitive genitive). The guests who were initially invited and refused are now permanently excluded from what they declined. The Lukan context makes the parable\'s referent clear: the Jewish leadership who have been invited to the kingdom feast and refused will not participate, while those they considered socially unworthy fill the hall.</p>',
    "25": '<p><strong>suneporeuonto de autō ochloi polloi</strong> — large crowds were travelling with him — the transitional verse marks a shift of audience from the Pharisee\'s dinner table to the road crowds. <em>Suneporeuomai</em> (travel together with — compound of <em>sun-</em> + <em>poreuomai</em>) implies the crowds are joining the journey movement; this is the Travel Narrative context (9:51ff). <em>Strapheis eipen pros autous</em> — turning he said to them — Luke\'s characteristic physical gesture-before-teaching (<em>strephō</em> = turn, also 7:9; 9:55; 10:23); the turn signals a direct and personally addressed teaching.</p>',
    "26": '<p><strong>ei tis erchetai pros me kai ou misei ton patera heautou kai tēn mētera</strong> — if anyone comes to me and does not hate his own father and mother — <em>misei</em> (hates — present indicative of <em>miseō</em>) is the strong word; its Semitic idiom background (comparative love: "hate" = "love less") is confirmed by the Matthew parallel (10:37: <em>ho philōn patera ē mētera hyper eme</em> = "who loves father or mother more than me"). The MKT "hate" renders the Aramaic underlying idiom faithfully while the Matthean version interprets it. <em>Eti te kai tēn psychēn heautou</em> — yes, even his own life — <em>psychē</em> (life, self) is added to the family list; self-attachment is the final attachment to be relativized by attachment to Jesus.</p>',
    "27": '<p><strong>hostis ou bastazei ton stauron heautou</strong> — whoever does not carry his own cross — <em>bastazō</em> (carry, bear — the carrying verb for burdens; cf. Gal 6:5; John 19:17 for Jesus carrying his cross) rather than Luke 9:23\'s <em>airō</em> (take up); both verbs describe cross-bearing but with different emphases: <em>airō</em> = taking up, <em>bastazō</em> = sustained carrying. The cross-bearing here is the discipleship condition stated before the two parables of cost-counting (tower, king); it frames the calculations as the concrete form of cross-bearing.</p>',
    "28": '<p><strong>tis ex hymōn thelōn purgon oikodomēsai</strong> — who among you, wanting to build a tower — <em>purgos</em> (tower — a watchtower, defensive tower, or tall farm-structure for guarding fields) as the construction project; the point is not architectural grandeur but any project requiring advance resource assessment. <em>Kathisas prōton psēphizei tēn dapanēn</em> — first sitting down counts the cost — <em>psēphizō</em> (count, calculate — from <em>psēphos</em> = pebble, voting-stone, used as a counting-token) is the financial calculation verb; <em>dapanē</em> (cost, expense — from <em>dapanaō</em> = spend, consume) is the sum to be counted before beginning.</p>',
    "29": '<p><strong>hina mēpote thentos autou themelion kai mē ischuontos ektelesai</strong> — lest after laying the foundation and not being able to finish — <em>themelion</em> (foundation — from <em>themis</em> = law, established order; the base on which something stands) + <em>ektelesai</em> (finish completely — intensive compound of <em>ek-</em> + <em>teleō</em> = complete thoroughly). The incomplete tower is the parable\'s embarrassing failure case; the Lukan context suggests that half-committed discipleship — starting without counting the cost — produces the same visible failure.</p>',
    "30": '<p><strong>houtos ho anthrōpos ērxato oikodomein kai ouk ischusen ektelesai</strong> — this man began to build and was not able to finish — the imperfect <em>ērxato</em> (began — past inception) + aorist <em>ischusen</em> (was able) creates the completed failure: he started (imperfect progress) but could not finish (aorist finality). <em>Empaizein autō</em> — mock him — <em>empaizō</em> (mock, ridicule — from <em>en</em> + <em>paizō</em> = play; playing at someone\'s expense) is the honor-destruction verb; the same word is used for the soldiers mocking Jesus (22:63; 23:11, 36).</p>',
    "31": '<p><strong>ē tis basileus poreuomenos hetō basilei symbalein eis polemon</strong> — or what king, going to engage another king in war — the second parable of calculation shifts from private construction to royal military strategy. <em>Symballō</em> (engage, meet — literally "throw together"; the military idiom is "engage in battle") with <em>eis polemon</em> (into war). <em>Ei dynatai en deka chiliasin hypantēsai tō meta eikosi chiliadeōn</em> — whether he is able with ten thousand to meet the one coming with twenty thousand — the force ratio (1:2) makes the calculation concrete; the weaker king must assess before the armies meet.</p>',
    "32": '<p><strong>ei de mēge, eti autou porrō ontos presbeian aposteilas erōta ta pros eirēnēn</strong> — if not, while the other is still far away, sending an embassy he asks for peace terms — <em>presbeia</em> (embassy, delegation — from <em>presbys</em> = old, elder; an embassy of elders) + <em>aposteilas</em> (having sent) + <em>erōtaō ta pros eirēnēn</em> (ask for the things toward peace). The king who cannot win asks for terms before the battle; the discipleship application is that following Jesus requires calculating whether one can sustain what is required — and if not, to surrender fully rather than partially.</p>',
    "33": '<p><strong>pas ex hymōn hos ouk apotassetai pasin tois heautou hyparchousin</strong> — everyone who does not renounce all his own possessions — <em>apotassomai</em> (renounce, take leave of, bid farewell to — from <em>apo-</em> + <em>tassō</em> = put in order; to arrange for departure, hence renounce/relinquish) appears also in 9:61 (the third would-be disciple asking to say goodbye). <em>Tois heautou hyparchousin</em> (all his own belongings — <em>hyparchō</em> = exist, belong to) is the possessions-word used throughout Luke (8:3; 12:15, 33, 44; 16:1; 19:8). The application lands harder than the parables: the tower-builder counts the cost before building; the disciple must count the cost and then relinquish everything.</p>',
    "34": '<p><strong>kalon oun to halas, ean de kai to halas mōranthē</strong> — salt is good, but if the salt becomes foolish/tasteless — <em>halas</em> (salt — the Greek word; also <em>hals</em> in some forms) is the agricultural and preservation material; in Galilee it was often impure, mixed with other minerals, and could lose its sodium chloride content through leaching, leaving only the tasteless mineral residue. <em>Mōrainō</em> (become foolish, become tasteless — from <em>mōros</em> = foolish, dull; the same root as English "moron") is the double-meaning word: salt that loses its saltiness has become "foolish" — the metaphor and the moral judgment are encoded in the same word.</p>',
    "35": '<p><strong>oute eis gēn oute eis koprian eutheton estin</strong> — it is fit neither for the soil nor for the manure pile — <em>euthetos</em> (fit, suitable, useful — from <em>eu-</em> + <em>tithēmi</em> = well-placed) with the double negative: tasteless salt fails at both its primary use (seasoning, preservation) and as a soil amendment (salt was sometimes used in compost in small quantities, but insipid mineral residue has no value). <strong>ho echōn ōta akouein akouetō</strong> — whoever has ears to hear, let them hear — Luke\'s standard call-to-attention formula (also 8:8; 13:9); the salt metaphor concludes the discipleship section of chapter 14 with the same urgency-marker as the parable section of chapter 8.</p>'
  },
  "15": {
    "1": '<p><strong>ēsan de autō engizoontes pantes hoi telōnai kai hoi hamartōloi akouein autou</strong> — all the tax collectors and sinners were drawing near to him to hear him — <em>telōnai</em> (tax collectors — from <em>telos</em> = tax/toll + <em>oneō</em> = buy; they purchased the right to collect taxes and profited by overcharging) are regularly paired with <em>hamartōloi</em> (sinners) throughout Luke (5:30; 7:34; 15:1-2; 18:11); the pairing is a fixed social category in the Pharisaic worldview. <em>Engizō</em> (draw near — Luke\'s approach verb) is the movement of those coming to Jesus throughout the Gospel; it is the opposite of the Pharisees\' watching distance (14:1).</p>',
    "2": '<p><strong>kai diegongyzon hoi Pharisaioi kai hoi grammateis legontes</strong> — and the Pharisees and scribes were grumbling — <em>diagongyzō</em> (grumble, mutter — intensive compound of <em>gongyzō</em> = grumble/murmur, the LXX word for Israel\'s wilderness murmuring; <em>dia-</em> prefix intensifies) links the Pharisees\' protest directly to the wilderness generation\'s murmuring against Moses (Exod 16:7-9; Num 11:1). <strong>houtos hamartōlous prosdechetai kai synesthiei autois</strong> — this man receives sinners and eats with them — <em>prosdechomai</em> (receive, welcome — from <em>pros-</em> + <em>dechomai</em> = receive toward oneself; to actively welcome) + <em>synesthiō</em> (eat with, share table — compound of <em>sun-</em> + <em>esthiō</em>): table-fellowship with sinners implies acceptance and solidarity, which is the Pharisaic complaint.</p>',
    "3": '<p><strong>eipen de pros autous tēn parabolēn tautēn legōn</strong> — he told them this parable — <em>tautēn</em> (this — singular) before the three parables: Luke treats the lost sheep, lost coin, and prodigal son as a single parable-sequence (<em>tēn parabolēn tautēn</em> in the singular) responding to the single complaint of v.2. The three parables are a triptych, each intensifying the theme: a man loses a sheep (external), a woman loses a coin (domestic), a father loses a son (relational/existential). Each recovery triggers communal celebration; each celebration is the narrative icon of heaven\'s rejoicing.</p>',
    "4": '<p><strong>tis anthrōpos ex hymōn echōn hekaton probata</strong> — what man among you having a hundred sheep — the rhetorical address <em>tis ex hymōn</em> (who among you) draws the listener into the scenario as the owner; the question assumes the obvious answer. <em>Hekaton probata</em> (a hundred sheep) represents a mid-sized flock in ancient Palestine; not a wealthy shepherd but a working-class owner for whom the loss of one is significant. <strong>katalipōn ta enenēkonta ennea</strong> — leaving the ninety-nine — <em>katalipōn</em> (aorist participle of <em>kataleipō</em> = leave behind, abandon temporarily) — the shepherd\'s paradox: protecting ninety-nine by leaving them to find one; the logic of disproportionate pursuit.</p>',
    "5": '<p><strong>kai heurōn epitithēsin epi tous ōmous autou chairōn</strong> — and finding it he puts it on his shoulders rejoicing — <em>epitithēsin epi tous ōmous</em> (puts on the shoulders — <em>ōmos</em> = shoulder; the shepherd carries the sheep rather than driving it) is the image of complete rescue, not just location; the lost sheep is carried back because it cannot find its own way. <em>Chairōn</em> (rejoicing — present participle, indicating continuous joy during the return journey) — the joy begins at the moment of finding, before the communal celebration. Luke\'s word choice emphasizes the joy as intrinsic to the recovery itself.</p>',
    "6": '<p><strong>kai elthōn eis ton oikon synkalei tous philous kai tous geitonas</strong> — and coming home he calls together friends and neighbors — the community celebration (<em>synkaleō</em> = call together) is the social expression of the private joy that began at finding. <strong>sugchārēte moi</strong> — rejoice with me — <em>sunchairō</em> (rejoice together with — compound of <em>sun-</em> + <em>chairō</em>); the invitation to shared joy reflects the honor-shame social fabric: significant events (recovery, rescue, restoration) are communal events. <em>Hoti heuron to probaton mou to apolōlos</em> — because I have found my lost sheep — <em>apolōlos</em> (perfect participle of <em>apollymi</em> = lost, destroyed; "the having-been-lost"); the perfect tense marks the permanent state of lostness that has now been reversed.</p>',
    "7": '<p><strong>legō hymin hoti houtōs chara en tō ouranō estai</strong> — I say to you that in this way there will be joy in heaven — <em>houtōs</em> (in this way, similarly) draws the comparison: as the shepherd celebrated, so heaven celebrates. <em>Chara en tō ouranō</em> (joy in heaven — a divine-euphemism: "heaven" = God rejoicing) is the theological claim behind the parable. <strong>ē epi enenēkonta ennea dikaiois hoi ouk echousin chreian metanoias</strong> — more than over ninety-nine righteous persons who have no need of repentance — the ninety-nine "righteous" is ironic in context: the Pharisees are the self-identified righteous who consider themselves beyond needing repentance, and the parable implies their status may not be what they think.</p>',
    "8": '<p><strong>ē tis gynē drachmas echousa deka ean apolesē drachmen mian</strong> — or what woman having ten silver coins if she loses one — the second parable shifts from male-outdoor (shepherd, fields) to female-domestic (woman, house). <em>Drachma</em> (a Greek silver coin ≈ one day\'s wage; the Roman <em>denarius</em> equivalent) — the ten-coin collection may represent a household savings or a woman\'s headdress ornament (coins sewn on a wedding headdress were a dowry symbol). The domestic setting (<em>oikia</em> = house) requires lamp and broom; the search is interior and careful rather than outdoor and ranging.</p>',
    "9": '<p><strong>kai heurasa synkalei tas philas kai geitonas</strong> — and finding it she calls together the friends and neighbors — the exact communal-celebration structure mirrors the shepherd\'s (v.6): <em>synkaleō</em> (call together) + <em>philas kai geitonas</em> (friends and neighbors — feminine plural, the woman\'s social network). The three-parable sequence uses the same celebration formula for all three: shepherd (v.6), woman (v.9), father (v.23-24), building from small group to large party. Each celebration is both the parable\'s resolution and the icon of heaven\'s joy.</p>',
    "10": '<p><strong>houtōs legō hymin, ginetai chara enōpion tōn angelōn tou theou</strong> — in this way I say to you, there is joy in the presence of the angels of God — Luke varies the divine-euphemism: v.7 says "joy in heaven"; v.10 says "joy in the presence of the angels of God" (<em>enōpion tōn angelōn tou theou</em>). <em>Enōpion</em> (in the presence of, before) is Luke\'s characteristic positional word (1:15, 17; 4:7; 5:25; 16:15); "the angels of God" is a circumlocution for God\'s presence (the heavenly court), parallel to "heaven" in v.7. <em>Epi heni hamartōlō metanoounti</em> — over one sinner who repents — the singular <em>heni</em> (one) emphasizes that individual restoration, not mass movement, provokes divine joy.</p>',
    "11": '<p><strong>anthrōpos tis eichen duo huious</strong> — a certain man had two sons — the barest narrative introduction; Luke uses <em>anthrōpos tis</em> (a certain man) for parables featuring a representative human figure (14:16; 16:1; 16:19). The two sons immediately set up the contrast structure: the younger who departs and returns vs the older who remains and resents. The father is the parable\'s central figure but is introduced only through his relation to the sons. The parable has no received title in the ancient sources; "Prodigal Son" is a Reformation-era label.</p>',
    "12": '<p><strong>dos moi to epiballon meros tēs ousias</strong> — give me the share of the estate that falls to me — <em>epiballon</em> (falling to, belonging to — present participle of <em>epiballō</em> = throw upon, belong to by right; here the inheritance share that "falls upon" the younger son). <em>Ousia</em> (estate, property, substance — from <em>eimi</em> = be; "being-ness," what constitutes one\'s material existence) is the word for the full property being divided. In Jewish law (Deut 21:17) the younger son\'s share is one-third; the request is extraordinary but not without legal basis. <em>Dieilen autois ton bion</em> — he divided the livelihood between them — <em>bios</em> (life, livelihood — material sustenance, not spiritual life; contrast <em>zoē</em> = life) is what is divided: the living that sustains existence.</p>',
    "13": '<p><strong>diaskorpisas tēn ousian autou zōn asōtōs</strong> — squandering his property living recklessly/prodigally — <em>diaskorpizō</em> (scatter, squander — from <em>dia-</em> + <em>skorpizō</em> = scatter; to throw in all directions, disperse completely; also used for the shepherd scattering the sheep, Matt 26:31) is the waste verb. <em>Asōtōs</em> (prodigally, recklessly, dissolutely — adverb from <em>asōtos</em> = one who cannot be saved/is past saving; from <em>a-</em> + <em>sōzō</em> = not-saving; the prodigal title derives from this word) is the English "prodigal" itself: <em>prodigus</em> (Latin) ≈ <em>asōtos</em> (Greek) = one who throws everything away, past saving by ordinary means.</p>',
    "14": '<p><strong>limos ischuros kata tēn chōran ekeinēn</strong> — a severe famine came upon that region — <em>limos ischuros</em> (powerful/severe famine — <em>ischuros</em> = strong, mighty; the same word for the stronger man at 11:22) intensifies the son\'s destitution: his self-caused poverty is compounded by external disaster. <em>Hyperistato</em> (he began to fall short, to be in need — imperfect of <em>hypereomai</em>); the imperfect describes the onset of progressive need. Luke presents the famine not as punishment but as context that reveals the depth of the son\'s situation.</p>',
    "15": '<p><strong>ekollēthē heni tōn politōn tēs chōras ekeinēs</strong> — he attached himself to one of the citizens of that region — <em>kollaō</em> (cling to, attach to, join — from <em>kolla</em> = glue; to glue oneself to someone, join urgently; also used for cleaving to a spouse and for the prodigal\'s clinging to the citizen). The citizen sends him to feed pigs (<em>boskein choirous</em>) — the supreme Jewish degradation: pigs are unclean animals (Lev 11:7) and pig-herding in a foreign land signals total defilement and social humiliation. The son who had an inheritance is now a pig-herder in Gentile territory.</p>',
    "16": '<p><strong>epethymei chortasthēnai ek tōn keratōn hōn ēsthion hoi choiroi</strong> — he longed to fill himself from the pods that the pigs were eating — <em>epithumeō</em> (desire earnestly, long for — the strong desire verb, also used for the Passover longing at 22:15) + <em>chortasthēnai</em> (to be filled/satisfied — from <em>chortos</em> = fodder, grass; animal satisfaction; also the feeding miracle verb). <em>Kerata</em> (pods — the carob pods of the carob tree, <em>Ceratonia siliqua</em>; cheap pig fodder and poor-person food in antiquity) = the English "prodigal" itself; no one gave him even this. <em>Kai oudeis edidou autō</em> — and no one gave him anything — the social isolation is total; he cannot even receive the level of charity given to strangers.</p>',
    "17": '<p><strong>eis heauton de elthōn ephē</strong> — coming to himself he said — <em>eis heauton de elthōn</em> (coming to himself — literally "coming into himself") is a Greek idiom for recovering one\'s senses, regaining awareness; it is used in Greek literature for returning to right judgment after madness or delirium. The son\'s repentance begins not with guilt about God but with practical calculation: how many of my father\'s hired servants have surplus food while I am perishing here? The movement from self-deception to self-knowledge is the beginning of return.</p>',
    "18": '<p><strong>anastas poreusomai pros ton patera mou</strong> — rising I will go to my father — <em>anastas</em> (rising — aorist participle of <em>anistēmi</em>; the resurrection verb; used for arising from sleep, from a seat, and from the dead) + <em>poreusomai</em> (I will go — future, a firm intention). The rise-and-go combination (<em>anastas + poreuomai</em>) occurs at significant turning points in Luke (1:39; 10:35; 15:20). <em>Hēmarton eis ton ouranon kai enōpion sou</em> — I have sinned against heaven and before you — the double object: heaven (<em>ouranon</em> = God-euphemism) and before you (the father); the sin is both vertical and horizontal.</p>',
    "19": '<p><strong>ouketi eimi axios klēthēnai huios sou</strong> — I am no longer worthy to be called your son — <em>axios</em> (worthy, deserving — the worth/merit word) in the negative: the son has forfeited the relational standing. His proposed remedy: <em>poiēson me hōs hena tōn misthiōn sou</em> (make me as one of your hired servants — <em>misthios</em> = hired worker, day-laborer; contrast <em>doulos</em> = slave born into the household; a hired worker is the lowest free status). The son calculates that servant-status with his father\'s household is better than freedom in the far country.</p>',
    "21": '<p><strong>eipen de ho huios autō, Pater, hēmarton eis ton ouranon kai enōpion sou</strong> — the son said to him: Father, I have sinned against heaven and before you — the son delivers his prepared speech (vv.18-19) but the father interrupts before the servant-request can be delivered. Compare v.19 and v.21: the son\'s scripted speech planned to say "make me a servant," but the father\'s action (v.22) preempts the negotiated-status request with full restoration. The incomplete speech captures the gap between the son\'s self-assessment and the father\'s response.</p>',
    "22": '<p><strong>exenegkate stolin tēn prōtēn</strong> — bring out the best robe — <em>stolē</em> (robe, long garment — from <em>stellō</em> = put in order, equip; a formal or festive garment; used for the rich man\'s clothing at 20:46; the resurrection angels at Mark 16:5) with the superlative <em>prōtēn</em> (first, finest) — the best robe in the household, not a servant\'s garment. <strong>dote daktylion eis tēn cheira autou kai hypodēmata eis tous podas</strong> — put a ring on his hand and sandals on his feet — ring: authority and family membership (a signet ring, <em>daktylios</em>); sandals: free man\'s mark (slaves went barefoot). The three items (robe, ring, sandals) together constitute full restoration of sonship status.</p>',
    "23": '<p><strong>kai pherete ton moschon ton siteuton thysate</strong> — bring the fattened calf and slaughter it — <em>moschos</em> (calf) + <em>siteuton</em> (fattened — from <em>siteuō</em> = fatten by grain-feeding; the most prized meat animal, kept for major celebrations). The fattened calf (reserved for special occasions, not daily meals) signals that the celebration is the highest-register festive event the household can produce. <em>Phagontes euphrainthōmen</em> — let us eat and be merry — <em>euphrainō</em> (rejoice, celebrate — the festivity verb; also vv.24, 29, 32; Luke 12:19; 16:19); the eating and rejoicing are the celebratory response to the restoration.</p>',
    "24": '<p><strong>hoti houtos ho huios mou nekros ēn kai anezēsen</strong> — for this son of mine was dead and has come back to life — <em>nekros ēn</em> (was dead — the complete lostness is named death) + <em>anezēsen</em> (came back to life — aorist of <em>anazaō</em> = live again, revive; re-animation verb). The dead/alive + lost/found couplet (<em>apolōlos ēn kai heurethē</em>) is the parable\'s thematic core and is repeated at v.32. <em>Kai ērxanto euphrainesathai</em> — and they began to celebrate — the imperfect <em>ērxanto</em> (began) + the festivity verb: the celebration starts immediately and continues.</p>',
    "25": '<p><strong>ēn de ho huios autou ho presbuteros en agrō</strong> — his older son was in the field — <em>presbuteros</em> (older, elder) son as the parable\'s second major character introduced only after the younger son\'s restoration is underway; the delay in introducing him makes the contrast sharp. <em>Agros</em> (field) is the place of faithful labor; the older son has been working while the younger was wasting his inheritance in the far country. <em>Hōs de erchomenos ēggisen tē oikia ēkousen symphōnias kai chorōn</em> — as he came near the house he heard music and dancing — <em>symphōnia</em> (music, harmony — musical performance; borrowed from Greek <em>symphōneō</em> = sound together) + <em>choros</em> (dance, dancing group).</p>',
    "26": '<p><strong>proskalesmenos hena tōn paidōn epynthaneto ti an eiē tauta</strong> — calling one of the servants he asked what these things might be — <em>proskaleomai</em> (call to oneself, summon — Luke\'s call-to-oneself verb) + <em>pyntanomai</em> (inquire, ask — the formal inquiry verb; also Acts 23:20; Matt 2:4). The optative <em>ti an eiē tauta</em> (what these things might be — oblique optative in indirect question) is classical Greek syntax that Luke preserves; the older son does not know yet what has happened because no one has told him.</p>',
    "27": '<p><strong>ho adelphos sou hēkei kai ethusen ho patēr sou ton moschon ton siteuton</strong> — your brother has come and your father has slaughtered the fattened calf — the servant reports two things: the brother\'s return (<em>hēkei</em> — perfect with present sense: "he is here") and the father\'s action (slaughter of the fattened calf). <em>Hygiainonta auton apelabon</em> — he received him back in good health — <em>hygiainō</em> (be in good health, be sound — from which <em>hygienic</em>; the "healthy" verb; contrast the physical and spiritual sickness implicit in the far-country life). The father\'s joy is expressed through the highest celebration available.</p>',
    "28": '<p><strong>ōrgisthē kai ouk ēthelen eiselthein</strong> — he became angry and was not willing to go in — <em>orgizō</em> (become angry — the full-anger word, also 14:21). The older son\'s refusal to enter (<em>ouk ēthelen eiselthein</em> — imperfect of <em>thelō</em> = was not willing; sustained unwillingness, not a momentary refusal) is its own honor-challenge: refusing to participate in the father\'s celebration is a public dishonoring of the father. <em>Ho de patēr autou exelthōn parekalei auton</em> — his father came out and was pleading with him — <em>parakaleō</em> (plead, urge, encourage — the same word for the Holy Spirit as Paraclete) in the imperfect: sustained pleading.</p>',
    "29": '<p><strong>idou tosauta etē douleuō soi kai oudepote entolēn sou parēlthon</strong> — look, so many years I have been serving you like a slave and I never transgressed your command — <em>douleuō</em> (serve as a slave — from <em>doulos</em>; the older son describes his faithful service in slave-vocabulary; he has been a faithful <em>doulos</em> while calling himself a son). <em>Oudepote entolēn sou parēlthon</em> (I never transgressed your command — <em>parerchomai</em> = pass by, transgress; also 11:42 for tithing while neglecting justice). <em>Emoigde eriphon oudepote edōkas</em> — you never gave me even a young goat — <em>eriphos</em> (young goat — the lowest-value festive animal; far less than the fattened calf given for his brother).</p>',
    "30": '<p><strong>ho de huios sou houtos ho kataphagōn sou ton bion meta pornōn</strong> — but this son of yours who has devoured your livelihood with prostitutes — the older son does not say "my brother" but "this son of yours" (<em>ho huios sou houtos</em>) — the deliberate distance is the emotional core of his resentment. <em>Kataphagōn</em> (devoured — intensive compound of <em>kata-</em> + <em>phagō</em> = eat down, consume completely) + <em>ton bion</em> (the livelihood; the same <em>bios</em> word as v.12). <em>Meta pornōn</em> (with prostitutes) — the older son\'s accusation; the parable text at v.13 said only "reckless living" (<em>asōtōs</em>); "prostitutes" is the older son\'s interpretation, possibly projecting, possibly inferring.</p>',
    "31": '<p><strong>teknon, su pantote met emou ei kai panta ta ema sa estin</strong> — child, you are always with me and everything I have is yours — the father\'s address <em>teknon</em> (child, dear child — the affectionate diminutive of family intimacy; not <em>huie</em> = son, but <em>teknon</em> = child, the intimate family word; also used in 2:48; 16:25) signals warmth rather than rebuke. <em>Panta ta ema sa estin</em> — everything I have is yours — the father\'s statement of the older son\'s standing: the inheritance is secure, the relationship is unbroken, the proximity (always with me) is the gift the younger son abandoned. The contrast reveals the older son\'s failure to receive what he already had.</p>',
    "32": '<p><strong>euphranthenai de kai charēnai edei</strong> — it was necessary to celebrate and rejoice — <em>edei</em> (it was necessary, it had to be — the divine necessity word, also 4:43; 9:22; 13:33; 22:37; 24:7; 24:26) applied to the celebration: the father\'s party is not optional sentiment but necessary response to the dead-alive reversal. The closing couplet (<em>nekros ēn kai ezēsen, apolōlos kai heurethē</em> — was dead and lived, was lost and was found) exactly repeats the father\'s exclamation of v.24: both halves of the parable end with the same formula. The parable ends without resolving the older son\'s response — his choice remains open, as does the Pharisees\'.</p>'
  },
  "16": {
    "1": '<p><strong>oikonomos</strong> — manager, steward — <em>oikonomos</em> (manager, steward of a household — from <em>oikos</em> = house + <em>nomos</em> = law/management; the one who manages the house\'s affairs; from which "economy") is the key term for the entire parable. The manager does not own the property but is entrusted to administer it; his accountability to the master is the parable\'s framing tension. <em>Diaskorpizōn ta hyparchonta autou</em> — squandering his possessions — the same <em>diaskorpizō</em> (scatter, squander) used for the prodigal son\'s waste (15:13); the parable is deliberately set after the prodigal and echoes its vocabulary.</p>',
    "2": '<p><strong>apodos ton logon tēs oikonomias sou</strong> — give an account of your management — <em>logon tēs oikonomias</em> (account of the stewardship — <em>logos</em> = word, account, reckoning; <em>oikonomia</em> = management, stewardship; from which "economy") is the formal audit demand. <em>Ouketi dunasai oikonomein</em> — you can no longer be manager — the dismissal is announced before the account is given, based on the accusation alone. The manager\'s crisis is not whether the accusation is true but what to do now that his position is ending: the parable\'s cleverness lies in the manager\'s resourceful response to irreversible termination.</p>',
    "3": '<p><strong>ti poiēsō, hoti ho kyrios mou aphaireitai tēn oikonomian ap emou</strong> — what shall I do, since my master is taking away the management from me — the interior monologue (<em>eipen en heautō</em> = said to himself; also 12:17 for the rich fool; 15:17 for the prodigal) is Luke\'s device for revealing the character\'s reasoning process. <em>Skaptein ouk ischuō, epaitein aischunomai</em> — I cannot dig, I am ashamed to beg — <em>skaptō</em> (dig — manual labor; the manager is a white-collar figure, not a field-worker) + <em>epaitō</em> (beg — from <em>epi-</em> + <em>aitō</em> = ask for; beg insistently); the two rejected options frame his social position: above manual labor by profession but too proud for begging.</p>',
    "4": '<p><strong>egnōn ti poiēsō</strong> — I know what I will do — the manager\'s decision arrives as a flash of insight (<em>egnōn</em> = I know/came to know — aorist of <em>ginōskō</em>; the moment of recognition). <em>Hina hotan metastathō tēs oikonomias dexōntai me eis tous oikous autōn</em> — so that when I am removed from the stewardship they will receive me into their homes — <em>metastathō</em> (when I am removed — aorist passive subjunctive of <em>methistēmi</em> = remove, displace; also Acts 13:22 for removing Saul) + <em>dechomai eis oikous</em> (receive into homes — the hospitality word): by generating debtor-gratitude before dismissal, he secures future hospitality.</p>',
    "5": '<p><strong>proskalesmenos hena hekaston tōn chreopheiletōn tou kyriou heautou</strong> — calling in each one of his master\'s debtors — <em>chreopheiletēs</em> (debtor — from <em>chreos</em> = debt + <em>opheiletēs</em> = one who owes; the compound = one who owes a debt; hapax in Luke, also 7:41 in the two-debtors parable). The manager calls each debtor privately (<em>hena hekaston</em> = each one, one by one) — the process is individual and confidential, suggesting the manager wants to minimize visibility of his scheme. <em>Posō opheileis tō kyriō mou</em> — how much do you owe my master — the inquiry is the setup for the reduction.</p>',
    "6": '<p><strong>hekaton batous elaiou... pentēkonta</strong> — a hundred measures of oil... fifty — <em>batos</em> (bath — a Hebrew liquid measure, approx. 8-9 gallons / 30-35 liters; 100 baths ≈ 800+ gallons of olive oil, a large commercial quantity). The reduction from 100 to 50 is 50% — a massive forgiveness of debt. <em>Dexai sou ta grammata kai kathisas tacheōs grapson pentēkonta</em> — take your bill, sit down quickly, and write fifty — <em>gramma</em> (written document, bill — from <em>graphō</em>; the bond or promissory note that establishes the debt) must be rewritten by the debtor himself (not the manager), which may be important legally — the debtor re-writes the obligation and thus creates a new document.</p>',
    "7": '<p><strong>hekaton korous sitou</strong> — a hundred kors of wheat — <em>koros</em> (cor — a Hebrew dry measure, approx. 10-12 bushels; 100 cors ≈ 1000-1200 bushels of wheat, a very large agricultural quantity). The reduction to 80 (20% less than oil\'s 50% reduction) may reflect different interest rates on the two commodities, or different profit margins the manager had taken. Various interpretations exist: (1) the debts represent illegal interest (usury) that the manager removes, legitimizing the reduction; (2) the manager forgoes his own commission, which was built into the inflated debt; (3) simple forgiveness to generate gratitude.</p>',
    "8": '<p><strong>epēnesen ho kyrios ton oikonomon tēs adikias</strong> — the master commended the dishonest manager — the interpretive crux: who is <em>ho kyrios</em> (the master)? If the master of the parable, the commendation is for shrewdness in crisis management; if Jesus himself is speaking as <em>kyrios</em>, it is direct authorial commendation. <em>Phronimōs epoiēsen</em> — acted shrewdly — <em>phronimōs</em> (shrewdly, wisely — from <em>phronimos</em> = prudent, practical-minded; the "shrewd" word in the parable of the ten virgins, Matt 25:2-9) is the virtue of practical intelligence, not ethical virtue. <em>Hoi huioi tou aiōnos toutou phronimōteroi... eisin</em> — the sons of this age are shrewder than the sons of light — the comparison is pragmatic: worldly people apply more ingenuity to their material affairs than believers do to their eternal affairs.</p>',
    "9": '<p><strong>poiēsate heautois philous ek tou mamōna tēs adikias</strong> — make friends for yourselves from the mammon of unrighteousness — <em>mamōnas</em> (Mammon — Aramaic loanword <em>māmōnāʾ</em> = wealth, money, property; appears only at Matt 6:24 and Luke 16:9, 11, 13 in the NT; not a proper name or deity in Second Temple Judaism but an Aramaic term for material wealth that Jesus uses as if it were a master, hence the personification). <em>Tēs adikias</em> (of unrighteousness — the genitive characterizes the nature of worldly wealth: it belongs to the unrighteous age and participates in systemic injustice). <em>Skēnas aiōnious</em> (eternal tents/dwellings — <em>skēnē</em> = tent; the eternal version echoes the heavenly dwelling).</p>',
    "10": '<p><strong>ho pistos en elachistō kai en pollō pistos estin</strong> — the faithful in very little is also faithful in much — the faithfulness principle: <em>pistos</em> (faithful, trustworthy — from <em>pisteō</em> = trust, believe; <em>pistos</em> as an adjective of character = one who can be trusted) in the <em>elachistō</em> (least, smallest — superlative of <em>mikros</em>) predicts faithfulness in <em>pollō</em> (much). The logic is character-consistency: how one handles small matters reveals how one will handle large ones. The faithful-unfaithful antithesis repeats the manager\'s failure: he was unfaithful in small things (embezzlement) and would be unfaithful in large things (true wealth).</p>',
    "11": '<p><strong>ei oun en tō adikō mamōna pistos ouk egenesthe</strong> — if then you have not been faithful in the unrighteous mammon — <em>adikos mamōnas</em> (unrighteous mammon = worldly wealth, the money of the current age) is the test case for faithfulness: handling money honestly reveals whether one can be trusted with <em>to alēthinon</em> (the true, genuine — from <em>alētheia</em> = truth; the "real" as opposed to the "transient"). The contrast is between <em>adikos mamōnas</em> (unrighteous mammon = money) and <em>to alēthinon</em> (the genuine wealth = spiritual/eternal goods). Money is the training ground for the eternal.</p>',
    "12": '<p><strong>en tō allotriō pistos ouk egenesthe, to hymeteron tis hymin dōsei</strong> — if you have not been faithful with someone else\'s property, who will give you what is your own — <em>allotrion</em> (another\'s property, what belongs to another — from <em>allos</em> = other; what is alien to oneself) vs <em>hymeteron</em> (your own — the possessive pronoun): worldly wealth is not "ours" but belongs to another (God\'s world, administered for a time); the "our own" (<em>to hymeteron</em>) is what is genuinely ours in eternity. The faithful manager of another\'s property earns what will be truly his own.</p>',
    "13": '<p><strong>oudeis oiketēs dunatai dusi kyriois douleuein</strong> — no household servant can serve two masters — <em>oiketēs</em> (household servant — from <em>oikos</em> = house; one who belongs to the household, a domestic slave; the domestic version of <em>doulos</em>; also Acts 10:7; Rom 14:4; 1 Pet 2:18) rather than <em>doulos</em> (slave) — the distinction emphasizes the household-allegiance dimension. <strong>ē gar ton hena misēsei kai ton heteron agapēsei</strong> — for he will hate the one and love the other — <em>miseō/agapaō</em> (hate/love) as comparative-preference antonyms: complete devotion to one master produces functional hatred of the other. <em>Theō douleuein kai mamōna</em> — serve God and Mammon — the personification of Mammon as a rival <em>kyrios</em> (master) makes wealth-love equivalent to idolatry.</p>',
    "14": '<p><strong>ēkouon de tauta panta hoi Pharisaioi philargyroi ontes kai exemyktērizon auton</strong> — the Pharisees, who were money-lovers, heard all these things and sneered at him — <em>philargyros</em> (money-lover — from <em>phileō</em> = love + <em>arguros</em> = silver/money; the compound = lover of money; also 2 Tim 3:2) is Luke\'s diagnosis; the Pharisees\' monetary devotion makes them the illustration of serving Mammon. <em>Exemyktērizon</em> (sneered at, turned up the nose at — from <em>ek-</em> + <em>myktērizō</em> = to turn up the nose, sneer; from <em>myktēr</em> = nostril; the nose-turning gesture of contempt; also Gal 6:7 where God is not mocked/<em>myktērizetai</em>).</p>',
    "15": '<p><strong>hymeis este hoi dikaiountes heautous enōpion tōn anthrōpōn</strong> — you are the ones who justify yourselves before men — <em>dikaioō</em> (justify, declare righteous — from <em>dikaios</em> = just, righteous; the justification verb of Pauline theology, here used by Jesus for self-justification before human audiences). The Pharisees\' <em>dikaioō heautous</em> (self-justification) before human observers (<em>enōpion tōn anthrōpōn</em>) is contrasted with God\'s knowledge of hearts. <strong>ho de theos ginōskei tas kardias hymōn</strong> — God knows your hearts — <em>kardiognōstēs</em> (heart-knower) is used for God in Acts 1:24 and 15:8; here the verb form: God\'s heart-knowledge penetrates self-presentation.</p>',
    "16": '<p><strong>ho nomos kai hoi prophētai mechri Iōannou</strong> — the Law and the Prophets until John — the canonical phrase <em>ho nomos kai hoi prophētai</em> (the Law and the Prophets) = the OT as a whole; the temporal boundary is John the Baptist. <em>Apo tote hē basileia tou theou euangelizetai</em> — from then the kingdom of God is proclaimed — <em>euangelizō</em> (proclaim good news — the proclamation verb of Luke-Acts; also 4:18; 7:22; 9:6; 16:16). <strong>kai pas eis autēn biazetai</strong> — and everyone forces his way into it — <em>biazetai</em> (forces/is forced — from <em>biazō</em> = to use force; the verb can be middle [forces his way] or passive [is forced in]; the meaning is disputed: either eagerness/urgency of entry or violent opposition against the kingdom). The Matthew parallel (11:12: <em>hē basileia tōn ouranōn biazetai</em>) supports the violence/forcing reading.</p>',
    "17": '<p><strong>eukopōteron de estin ton ouranon kai tēn gēn parelthein</strong> — it is easier for heaven and earth to pass away — <em>eukopoteros</em> (easier — comparative of <em>eukopos</em> = easy; from <em>eu</em> + <em>kopos</em> = good-effort; the easy word; "easier" appears also in the camel-needle saying 18:25). <em>Parelthein</em> (pass away, pass by — aorist of <em>parerchomai</em> = pass beside, go past; also used for Jesus\'s words not passing away, 21:33). <em>Ē tou nomou mian keraian pesein</em> — than for one stroke of the pen to fall from the Law — <em>keraia</em> (stroke, horn-like mark — the tiny decorative mark on a Hebrew letter; the smallest unit of the Torah text; also Matt 5:18 in the "not one iota or keraia" saying). The Torah\'s permanence is established by comparison to cosmic stability.</p>',
    "18": '<p><strong>pas ho apolyōn tēn gynaika autou kai gamōn heteran moicheuei</strong> — everyone who divorces his wife and marries another commits adultery — <em>apolyō</em> (release, dismiss, divorce — the standard divorce verb; the formal release of a wife from the marriage bond under Jewish law). The saying appears here in Luke without the Matthean exception clause (<em>parektos logou porneias</em> = except for sexual immorality, Matt 5:32; 19:9). Luke\'s absolute form of the saying is a Greek legal formulation without the Jewish exception-clause debate context; it may address a different situation (Gentile divorce practice). <em>Kai ho apolelumenēn apo andros gamōn moicheuei</em> — and the man who marries a woman divorced from a husband commits adultery — the second clause extends the prohibition to the man who marries the divorced woman.</p>',
    "19": '<p><strong>anthrōpos de tis ēn plousios kai enedidysketo porphyran kai bussinon</strong> — there was a rich man who was dressed in purple and fine linen — <em>plousios</em> (rich — from <em>ploutos</em> = wealth; the rich-man word throughout Luke as the economic counterpart to <em>ptōchos</em> = poor). <em>Porphyran</em> (purple — the color of wealth and royalty; <em>porphyra</em> = the Tyrian purple dye extracted from sea snails at enormous expense; 10,000 snails for one gram of dye; the fabric therefore signaled extreme wealth) + <em>bussinon</em> (fine linen — from <em>byssos</em> = Egyptian fine linen, imported luxury fabric; also used for the Jerusalem temple curtain and the clothing of the righteous in Rev 19:8). <em>Euphrainomenos kath hēmeran lampros</em> — feasting sumptuously every day — the daily (<em>kath hēmeran</em>) sumptuousness (<em>lampros</em> = brilliantly, magnificently) characterizes excess rather than occasional celebration.</p>',
    "20": '<p><strong>ptōchos de tis onomati Lazaros ebeblēto pros ton pylōna autou</strong> — a poor man named Lazarus was laid at his gate — <em>Lazaros</em> (the Hellenized form of Hebrew <em>El-āzār</em> = God helps) is the only named character in any of Jesus\'s parables — the detail is significant; the rich man is unnamed throughout. <em>Ebeblēto</em> (pluperfect passive of <em>ballō</em> = throw; the pluperfect indicates a state already established: "was lying placed/thrown") at the gate (<em>pylōn</em> = gate, gateway — the grand entrance of a wealthy estate). The begging-posture (<em>ptōchos</em> = beggar, destitute — from <em>ptōssō</em> = crouch/cower; the destitute-beggar word, not merely economically poor) at the gate is the maximum social contrast to the purple-clad feaster within.</p>',
    "21": '<p><strong>epithymōn chortasthēnai apo tōn piptontōn apo tēs trapezēs tou plousiou</strong> — longing to be filled from what fell from the rich man\'s table — <em>epithumeō</em> (long for earnestly — the strong desire verb; also 15:16 for the prodigal\'s longing for pig-pods; 22:15 for Jesus\'s Passover longing) + <em>chortasthēnai</em> (to be filled/satisfied — the animal-satiety word; also 15:16; the miraculous feeding verb). <em>All kai hoi kynes erchomenoi apeleichon ta helkē autou</em> — even the dogs were coming and licking his sores — <em>helkos</em> (sore, wound, ulcer) + <em>apoleichō</em> (lick off — compound of <em>apo-</em> + <em>leichō</em> = lick). The dog-licking is ambiguous in the Greek: torment (unclean animals touching his wounds) or comfort (the only contact he receives).</p>',
    "22": '<p><strong>egeneto de apothanein ton ptōchon kai apenechthēnai auton hypo tōn angelōn</strong> — the poor man died and was carried by the angels — <em>apenechthēnai</em> (to be carried away — aorist passive infinitive of <em>apopherō</em> = carry away, bring away; the angelic transport verb) contrasts with the rich man\'s burial (<em>etaphē</em> = was buried). No burial is mentioned for Lazarus — in antiquity, burial was the transition to the honored afterlife; Lazarus\'s burial is omitted, foregrounded by angelic transport instead. <strong>eis ton kolpon Abraam</strong> — into Abraham\'s bosom/side — <em>kolpos</em> (bosom, chest, side — also John 1:18 for the Son "in the Father\'s bosom"; 13:23 for the Beloved Disciple reclining in Jesus\'s bosom at the Last Supper): the closest possible position to the covenant patriarch.</p>',
    "23": '<p><strong>en tō hadē eparas tous ophthalmous autou</strong> — in Hades, lifting up his eyes — <em>hadēs</em> (Hades — the Greek underworld/realm of the dead; adopted into Jewish afterlife vocabulary; in the LXX it translates <em>sheol</em>; in the NT, distinct from <em>gehenna</em> as the permanent place of destruction; Hades is the intermediate state or general underworld). <em>Eparas tous ophthalmous</em> (lifting up his eyes — the gesture of deliberate upward vision, also 6:20; 18:13) from below to see Abraham above. <strong>hora Abraam apo makrothen kai Lazaron en tois kolpois autou</strong> — he sees Abraham far away and Lazarus in his bosom — the spatial reversal is complete: the one who was at the gate below is now in the place of honor above; the rich man who feasted daily is now in torment below.</p>',
    "24": '<p><strong>pater Abraam, eleēson me</strong> — Father Abraham, have mercy on me — <em>eleēson me</em> (have mercy on me — aorist imperative of <em>eleaō</em> = show mercy/compassion; the same cry of the blind men and the Syrophoenician woman throughout the Gospels; the <em>kyrie eleison</em> of liturgical tradition) addressed to <em>pater Abraam</em> (Father Abraham — the Abrahamic-family claim). <em>Pempson Lazaron</em> — send Lazarus — the rich man still addresses Lazarus only through Abraham; he treats Lazarus as an errand-runner even in the afterlife, suggesting his social perception has not changed. <em>Hina bapsē to akron tou daktylou autou hydatos kai katapsyxē tēn glōssan mou</em> — to dip the tip of his finger in water and cool my tongue.</p>',
    "25": '<p><strong>teknon, mnēsthēti hoti apelabas ta agatha sou en tē zōē sou</strong> — child, remember that you received your good things in your lifetime — <em>teknon</em> (child — Abraham\'s address to the rich man is the same affectionate word the father used for the older son in 15:31; the warmth of the address sharpens the severity of the content). <em>Apelabas</em> (you received in full — aorist of <em>apolambanō</em> = receive back, receive in full; the prefix <em>apo-</em> implies complete receipt, payment-in-full). The reversal logic: goods received fully in this life; now the opposite. <em>Kai Lazaros homoiōs ta kaka nun de hōde parakaleitai</em> — Lazarus likewise received bad things, but now here he is comforted — <em>parakaleō</em> (be comforted, be encouraged — the Paraclete verb in its comfort function).</p>',
    "26": '<p><strong>en pasi toutois metaxy hēmōn kai hymōn chasma mega estēriktai</strong> — in all this, between us and you a great chasm has been fixed — <em>chasma</em> (chasm, gulf — from <em>chainō</em> = yawn, gape; a gaping void; only NT occurrence; the specific word for an unbridgeable geological void) + <em>mega</em> (great) + <em>estēriktai</em> (has been fixed/established — perfect passive of <em>stērizō</em> = set firm, establish; the same verb for Jesus setting his face toward Jerusalem at 9:51). The permanence (<em>stērizō</em> perfect) of the separation is its defining characteristic: the chasm is not temporary but set in place once death has established the final state.</p>',
    "27": '<p><strong>erōtō se oun, pater, hina pempsēs auton eis ton oikon tou patros mou</strong> — I beg you then, father, send him to my father\'s house — the rich man\'s second request shifts from personal relief to family warning; the petition is still through Abraham (<em>pempsēs auton</em> = send him), still treating Lazarus as a servant. <em>Erōtō</em> (I ask, I beg — from <em>erōtaō</em>; formal request verb) used for a serious petition. The family concern is genuine but comes too late and through the wrong channel; he cannot direct Lazarus any more than he could ignore him at his gate.</p>',
    "28": '<p><strong>echō gar pente adelphous, hopōs diamartyretai autois</strong> — for I have five brothers, so that he may warn them — <em>diamartyromai</em> (testify solemnly, warn emphatically — from <em>dia-</em> + <em>martys</em> = witness through; intensive testimony verb; also Acts 2:40; 8:25; 18:5; 20:23-24; 28:23) — the request is for solemn warning testimony to prevent the brothers from arriving at the same place of torment. The rich man\'s concern for others emerges only in extremis, and even here it is framed in terms of his own family rather than universal compassion.</p>',
    "29": '<p><strong>echousin Mōysea kai tous prophētas</strong> — they have Moses and the Prophets — the canonical phrase reappears (v.16): the OT witness (Torah + Prophets) as already sufficient. <em>Akousatōsan autōn</em> — let them listen to them — <em>akouō</em> (hear, listen, obey — the comprehensive hearing verb of Deuteronomy: <em>shema</em> = hear, obey) in the imperative. Abraham\'s point is that the Scriptures already contain everything necessary for repentance; the rich man\'s brothers have what is needed — they need only listen. The parable\'s argument is that the problem is not insufficient evidence but unwillingness to hear what is already available.</p>',
    "30": '<p><strong>ouchi, pater Abraam, all ean tis apo nekrōn poreuthē pros autous, metanoēsousin</strong> — no, Father Abraham, but if someone from the dead goes to them they will repent — <em>metanoeō</em> (repent, change mind — from <em>meta-</em> + <em>noeō</em> = change thinking; turn around in mind and direction; the repentance verb) as the goal of the desired apparition. The rich man\'s request for a post-mortem missionary implies that Scripture is insufficient — a direct contradiction of Abraham\'s position. The irony of the parable is prospective: <em>apo nekrōn</em> (from the dead) anticipates Jesus\'s own resurrection, which the religious leaders will reject despite being confronted with it.</p>',
    "31": '<p><strong>ei Mōyseōs kai tōn prophētōn ouk akouousin, oude ean tis ek nekrōn anastē peisthēsontai</strong> — if they do not hear Moses and the Prophets, neither will they be convinced if someone rises from the dead — <em>anastē</em> (rises — aorist active subjunctive of <em>anistēmi</em> = rise, stand up; the resurrection verb) from the dead (<em>ek nekrōn</em>) is the precise phrase for Jesus\'s resurrection throughout Luke-Acts (24:46; Acts 10:41; 17:3). <em>Peisthēsontai</em> (be convinced, be persuaded — future passive of <em>peithō</em> = persuade) — Abraham\'s final word predicts the historical outcome: the resurrection of Jesus will not persuade those who have already refused Moses and the Prophets (Luke 20:1-8; Acts 4:1-22).</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'luke')
    merge_comm(existing, LUKE_CH14_16)
    save_comm('mkt-original', 'luke', existing)
    ch14 = len(existing.get('14', {}))
    ch15 = len(existing.get('15', {}))
    ch16 = len(existing.get('16', {}))
    print(f'Luke 14: {ch14} verses, Luke 15: {ch15} verses, Luke 16: {ch16} verses.')

if __name__ == '__main__':
    main()
